SELECT id, applicant_id AS applicantId, applicant_name AS applicantName, applicant_phone AS applicantPhone, applicant_address AS applicantAddress, animal_id AS animalId, animal_name AS animalName, animal_type AS animalType, application_reason AS applicationReason, living_condition AS livingCondition, has_other_pets AS hasOtherPets, family_members AS familyMembers, work_situation AS workSituation, status, audit_time AS auditTime, auditor_id AS auditorId, auditor_name AS auditorName, audit_remark AS auditRemark, adoption_time AS adoptionTime, adoption_contract_no AS adoptionContractNo, is_deleted AS isDeleted, create_time AS createTime, update_time AS updateTime FROM adoption_application
is_deleted = 0
AND applicant_id = #{applicantId}
AND applicant_name LIKE concat('%', #{applicantName}, '%')
AND animal_id = #{animalId}
AND animal_name LIKE concat('%', #{animalName}, '%')
AND animal_type = #{animalType}
AND status = #{status}
ORDER BY create_time DESC
LIMIT #{current}, #{size}

